import { Box, Typography, LinearProgress, useMediaQuery } from '@mui/material'
import CustomDivider from '../../common/CustomDivider'
import { useTheme } from '@mui/material/styles'

const Skill = ({ name, color, value, icon }) => {
  const theme = useTheme()
  const isSx = useMediaQuery(theme.breakpoints.only('xs'))
  return (
    <>
      <CustomDivider
        icon={
          <Box component="img" src={icon} sx={{ height: isSx ? 20 : 30 }} />
        }
        label={name}
        color={color}
        align="right"
        sx={{ color: '#000', p: isSx ? 2 : 3 }}
      />
      <Box
        sx={{
          display: 'flex',
          p: 1,
          alignItems: 'center',
        }}
      >
        <Box sx={{ minWidth: 35 }}>
          <Typography variant="body2" color="text.primary">
            {Math.round(value)}%
          </Typography>
        </Box>
        <Box
          sx={{
            width: 1,
            minWidth: 35,
          }}
        >
          <LinearProgress
            variant="determinate"
            value={value}
            color={color}
            sx={{
              height: 10,
              borderRadius: 2,
            }}
          />
        </Box>
      </Box>
    </>
  )
}
export default Skill
